_BODY = '@torch.no_grad()\ndef sample_dbim(\n    denoiser,\n    diffusion,\n    x,\n    ts,\n    eta=1.0,\n    mask=None,\n    seed=None,\n    **kwargs,\n):\n    """Curvature-Adaptive Tempered ECSI (CATE) hybrid bridge sampler."""\n    x_T = x\n    path = [x.detach().cpu()]\n    pred_x0 = []\n    ones = x.new_ones([x.shape[0]])\n    ns = diffusion.noise_schedule\n    t_max = diffusion.t_max\n\n    # Low-rho ECSI grid.  We keep the bridge coefficients exact, changing only\n    # the stochastic/ODE split; return nfe must match the caller\'s expected name.\n    nfe = len(ts) - 1\n    n_grid = len(ts) - 1\n    rho_k = 0.6\n    sigma_min = 0.10 if mask is not None else 0.15\n    t_lo = max(float(diffusion.t_min), sigma_min)\n    t_hi = float(t_max) - 5e-4\n    ramp = torch.linspace(0.0, 1.0, n_grid, device=x.device, dtype=torch.float64)\n    ts_k = (t_hi ** (1.0 / rho_k) + ramp * (t_lo ** (1.0 / rho_k) - t_hi ** (1.0 / rho_k))) ** rho_k\n    ts = torch.cat([ts_k, torch.tensor([float(diffusion.t_min)], device=x.device, dtype=torch.float64)])\n\n    alpha_T = float(ns.alpha_T)\n    rho_T = float(ns.rho_T)\n    rho_T2 = rho_T * rho_T\n    generator = BatchedSeedGenerator(seed)\n    first_noise = generator.randn_like(x)\n\n    def _abc_deriv(t_scalar):\n        t = t_scalar.clamp(min=1e-6, max=float(t_max) - 1e-6) * ones\n        alpha, alpha_bar, rho, rho_bar = ns.get_alpha_rho(t)\n        alpha, alpha_bar, rho, rho_bar = [append_dims(v, x.ndim) for v in (alpha, alpha_bar, rho, rho_bar)]\n        f_t, g2_t = ns.get_f_g2(t)\n        f_t, g2_t = append_dims(f_t, x.ndim), append_dims(g2_t, x.ndim)\n        alpha_d = alpha * f_t\n        rho_d = 0.5 * (rho * rho + 1.0) * g2_t / rho\n        rho_sq, rho_bar_sq = rho * rho, rho_bar * rho_bar\n        a = alpha_bar * rho_sq / rho_T2\n        b = alpha * rho_bar_sq / rho_T2\n        c = alpha * rho_bar * rho / rho_T\n        alpha_bar_d = alpha_d / alpha_T\n        rho_bar_sq_d = -2.0 * rho * rho_d\n        rho_bar_d = -rho * rho_d / rho_bar\n        a_d = (alpha_bar_d * rho_sq + alpha_bar * 2.0 * rho * rho_d) / rho_T2\n        b_d = (alpha_d * rho_bar_sq + alpha * rho_bar_sq_d) / rho_T2\n        c_d = (alpha_d * rho_bar * rho + alpha * rho_bar_d * rho + alpha * rho_bar * rho_d) / rho_T\n        return (a, b, c), (a_d, b_d, c_d)\n\n    prev_x0 = None\n    n_steps = len(ts) - 1\n    indices = tqdm(range(n_steps), disable=(dist.get_rank() != 0))\n    for step_idx in indices:\n        s, t_next = ts[step_idx], ts[step_idx + 1]\n        x0_hat = denoiser(x, s * ones)\n        if mask is not None:\n            x0_hat = x0_hat * mask + x_T * (1 - mask)\n\n        (a_s, b_s, c_s), (a_d, b_d, c_d) = _abc_deriv(s)\n        if step_idx >= n_steps - 2:\n            a_t, b_t, c_t = [append_dims(v, x.ndim) for v in ns.get_abc(t_next * ones)]\n            z_hat = (x - b_s * x0_hat - a_s * x_T) / c_s\n            x = b_t * x0_hat + a_t * x_T + c_t * z_hat\n        else:\n            z_hat = (x - b_s * x0_hat - a_s * x_T) / c_s\n            base_eps = (c_s * c_d - (b_d / b_s) * c_s * c_s).clamp(min=0)\n            prog = float(step_idx) / max(float(n_steps - 1), 1.0)\n            snr_gate = (c_s / (b_s.abs() + c_s + 1e-8)).clamp(0.0, 1.0)\n            if prev_x0 is None:\n                curv_gate = 1.0\n            else:\n                delta = (x0_hat - prev_x0).flatten(1).pow(2).mean(1).sqrt()\n                scale = x0_hat.flatten(1).pow(2).mean(1).sqrt().clamp(min=1e-3)\n                curv_gate = append_dims(torch.exp(-1.6 * (delta / scale)).clamp(0.35, 1.0), x.ndim)\n            temp = (0.30 if mask is None else 0.22) * (1.15 - 0.55 * prog) * (0.65 + 0.70 * snr_gate) * curv_gate\n            eps = eta * temp * base_eps\n            dt = t_next - s\n            drift = b_d * x0_hat + a_d * x_T + (c_d + eps / c_s) * z_hat\n            x = x + drift * dt + (2.0 * eps).sqrt() * generator.randn_like(x) * dt.abs().sqrt()\n\n        if mask is not None:\n            x = x * mask + x_T * (1 - mask)\n        path.append(x.detach().cpu())\n        pred_x0.append(x0_hat.detach().cpu())\n        prev_x0 = x0_hat\n\n    return x, path, nfe, pred_x0, ts, first_noise\n'

